import{_ as t,o as a,c as i,ad as n}from"./chunks/framework.DdcUsuRQ.js";const m=JSON.parse('{"title":"CMYK","description":"The subtractive four-ink model iridis exposes as a picker affordance. Channel ranges, the K separation formula, and why no profile-aware math primitives ship.","frontmatter":{"title":"CMYK","description":"The subtractive four-ink model iridis exposes as a picker affordance. Channel ranges, the K separation formula, and why no profile-aware math primitives ship.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/cmyk"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/cmyk"}],["meta",{"property":"og:title","content":"CMYK: iridis"}],["meta",{"property":"og:description","content":"The subtractive four-ink model iridis exposes as a picker affordance. Channel ranges, the K separation formula, and why no profile-aware math primitives ship."}],["meta",{"name":"twitter:title","content":"CMYK: iridis"}],["meta",{"name":"twitter:description","content":"The subtractive four-ink model iridis exposes as a picker affordance. Channel ranges, the K separation formula, and why no profile-aware math primitives ship."}],["meta",{"name":"description","content":"The subtractive four-ink model iridis exposes as a picker affordance. Channel ranges, the K separation formula, and why no profile-aware math primitives ship."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"CMYK\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/cmyk\\"}]}"]]},"headers":[],"relativePath":"reference/cmyk.md","filePath":"reference/cmyk.md","lastUpdated":1779033869000}'),r={name:"reference/cmyk.md"};function s(o,e,c,d,p,h){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="cmyk" tabindex="-1">CMYK <a class="header-anchor" href="#cmyk" aria-label="Permalink to &quot;CMYK&quot;">​</a></h1><p>CMYK (cyan, magenta, yellow, key/black) is the subtractive process model used by four-color print. Each channel is the percentage of one ink laid on a white substrate. K is the black plate, separated out so that dark colors do not require saturating all three chromatic inks.</p><h2 id="coordinates" tabindex="-1">Coordinates <a class="header-anchor" href="#coordinates" aria-label="Permalink to &quot;Coordinates&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Channel</th><th>Range</th><th>Meaning</th></tr></thead><tbody><tr><td>C</td><td><code>[0, 1]</code> or <code>[0, 100]</code> percent</td><td>cyan ink coverage</td></tr><tr><td>M</td><td><code>[0, 1]</code> or <code>[0, 100]</code> percent</td><td>magenta ink coverage</td></tr><tr><td>Y</td><td><code>[0, 1]</code> or <code>[0, 100]</code> percent</td><td>yellow ink coverage</td></tr><tr><td>K</td><td><code>[0, 1]</code> or <code>[0, 100]</code> percent</td><td>black ink coverage</td></tr></tbody></table><p>CMYK is device-dependent. A real conversion needs an ICC profile for the target press, paper, and ink set. The browser-side approximation <span class="iridis-brand">iridis</span> uses is the standard naive transform with no profile applied, accurate enough for a UI control, not accurate enough to send to a printer.</p><h2 id="the-k-channel" tabindex="-1">The K channel <a class="header-anchor" href="#the-k-channel" aria-label="Permalink to &quot;The K channel&quot;">​</a></h2><p>Naive subtractive RGB → CMY would set <code>C = 1 − R</code>, <code>M = 1 − G</code>, <code>Y = 1 − B</code>. That works mathematically but is wasteful in practice: stacking three inks to render dark grey costs ink, dries slowly, and shifts hue. The K channel exists as the common minimum that gets pulled out of all three:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>K = 1 − max(R, G, B)</span></span>
<span class="line"><span>C = (1 − R − K) / (1 − K)</span></span>
<span class="line"><span>M = (1 − G − K) / (1 − K)</span></span>
<span class="line"><span>Y = (1 − B − K) / (1 − K)</span></span></code></pre></div><p>When <code>K = 1</code> (pure black), the chromatic channels are forced to zero to avoid division by zero. The reverse:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span>R = (1 − C) · (1 − K)</span></span>
<span class="line"><span>G = (1 − M) · (1 − K)</span></span>
<span class="line"><span>B = (1 − Y) · (1 − K)</span></span></code></pre></div><h2 id="math-primitives" tabindex="-1">Math primitives <a class="header-anchor" href="#math-primitives" aria-label="Permalink to &quot;Math primitives&quot;">​</a></h2><p><span class="iridis-brand">iridis</span> does not export CMYK math primitives. CMYK exists only in the picker as a numeric I/O affordance, designers occasionally want to see what a screen color looks like in CMYK terms even when the output is digital.</p><h2 id="where-it-appears" tabindex="-1">Where it appears <a class="header-anchor" href="#where-it-appears" aria-label="Permalink to &quot;Where it appears&quot;">​</a></h2><ul><li><code>IridisPicker.vue</code> (<code>docs/.vitepress/theme/components/IridisPicker.vue</code>) provides a CMYK tab. Edits convert through CMYK → RGB → hex and emit a fresh hex on every change.</li><li>The pipeline never receives CMYK input. There is no <code>intake:cmyk</code> task and no CMYK channel on <code>ColorRecord</code>.</li></ul>`,14)])])}const u=t(r,[["render",s]]);export{m as __pageData,u as default};
